content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一個袋子嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 yi1 ge4 dai4zi0 ma0?",
      "translation_en": "Excuse me, can you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나를 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Excuse me, can you add boba for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주실 수 있나요?"
    },
    {
      "text": "店員，可以給我菜單看一下嗎？",
      "pinyin": "Diànyuán, kěyǐ gěi wǒ càidān kàn yīxià ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 gei3 wo3 cai4dan1 kan4 yi1xia4 ma0?",
      "translation_en": "Staff, can you let me take a look at the menu?",
      "translation_ko": "직원분, 메뉴판을 좀 볼 수 있을까요?"
    },
    {
      "text": "我想要一杯中杯紅茶，半糖少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi hóngchá, bàn táng shǎo bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 hong2cha2, ban4 tang2 shao3 bing1, ke3yi3 ma0?",
      "translation_en": "I would like a medium black tea, half sugar and less ice, okay?",
      "translation_ko": "중간 컵 홍차 한 잔을 원하는데, 반당에 얼음 적게 해도 될까요?"
    },
    {
      "text": "請問，可以外帶一杯大杯綠茶嗎？",
      "pinyin": "Qǐng wèn, kěyǐ wài dài yī bēi dà bēi lǜchá ma?",
      "pinyin_numeric": "qing3 wen4, ke3yi3 wai4 dai4 yi1 bei1 da4 bei1 lü4cha2 ma0?",
      "translation_en": "Excuse me, can I get a large green tea to go?",
      "translation_ko": "실례합니다, 큰 컵 녹차 한 잔을 포장해 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以再說一次價錢嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì jiàqián ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 jia4qian2 ma0?",
      "translation_en": "Excuse me, can you say the price again?",
      "translation_ko": "죄송합니다, 가격을 한 번 더 말씀해 주실 수 있나요?"
    },
    {
      "text": "麻煩你，可以給我一根吸管嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī gēn xīguǎn ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0?",
      "translation_en": "Excuse me, can you give me a straw?",
      "translation_ko": "실례합니다, 빨대 하나를 주실 수 있나요?"
    },
    {
      "text": "我想要一杯豆漿，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dòujiāng, nèi yòng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4jiang1, nei4 yong4, ke3yi3 ma0?",
      "translation_en": "I would like a cup of soy milk, for here, okay?",
      "translation_ko": "두유 한 잔을 원하는데, 매장에서 마실게요, 괜찮을까요?"
    },
    {
      "text": "店員，可以幫我拿一張衛生紙嗎？",
      "pinyin": "Diànyuán, kěyǐ bāng wǒ ná yī zhāng wèishēngzhǐ ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 bang1 wo3 na2 yi1 zhang1 wei4sheng1zhi3 ma0?",
      "translation_en": "Staff, can you get me a tissue?",
      "translation_ko": "직원분, 휴지 한 장을 가져다 주실 수 있나요?"
    }
  ]
}
